-- Medium priority tables from MSSQL
-- Creates new tables: beginner_item, user_block_item_list, boss_event_summon_list
-- Seeds: MERCHANT_BOT_INFO (81), MERCHANT_BOT_ITEM (72), BOT_HANDLER_69Lv (2269)
-- Updates: DAMAGE_SETTINGS, ITEMUP_PROBABILITY

-- ==================== NEW TABLES ====================
-- BEGINNER_ITEM (5 rows)
CREATE TABLE IF NOT EXISTS beginner_item (
    i_class     SMALLINT NOT NULL PRIMARY KEY,
    class_name  VARCHAR(20) NOT NULL DEFAULT '',
    gold        BIGINT NOT NULL DEFAULT 0,
    str_item    BYTEA
);
-- USER_BLOCK_ITEM_LIST (25 rows)
CREATE TABLE IF NOT EXISTS user_block_item_list (
    user_id     VARCHAR(21) NOT NULL PRIMARY KEY,
    blocked_items INTEGER[] NOT NULL DEFAULT '{}'
);
-- BOSS_EVENT_SUMMON_LIST (100 rows)
CREATE TABLE IF NOT EXISTS boss_event_summon_list (
    b_index     INTEGER NOT NULL,
    zone_id     SMALLINT NOT NULL DEFAULT 0,
    sid_id      SMALLINT NOT NULL DEFAULT 0,
    sid_count   SMALLINT NOT NULL DEFAULT 1,
    pos_x       SMALLINT NOT NULL DEFAULT 0,
    pos_z       SMALLINT NOT NULL DEFAULT 0,
    spawn_range SMALLINT NOT NULL DEFAULT 0,
    wait_time   INTEGER NOT NULL DEFAULT 0,
    summon_name VARCHAR(50) NOT NULL DEFAULT ''
);
CREATE INDEX IF NOT EXISTS idx_boss_event_zone ON boss_event_summon_list(zone_id);
-- ==================== UPDATES ====================
